    if num == 0 {
        return "0".to_string();
    }
    let mut res = String::new();
    let mut n = num;
    while n > 0 {
        let remainder = n % base;
        let c = if remainder < 10 {
            (b'0' + remainder as u8) as char
        } else {
            (b'A' + (remainder - 10) as u8) as char
        };
        res = c.to_string() + &res;
        n = n / base;
    }
    res
}
